import React, { useState, useEffect, useCallback } from "react";
import "./DisplayRows.css";

const ParameterDisplay = ({ parameters: initialParameters, onPageChange, onFocusChange, activeFocus, setAutoModeExternal, currentPage }) => {
  var UPDATE_INTERVAL_MS = 200;
  var ITEMS_PER_PAGE = 4;
  var SKIP_COUNT = 6;

  // Force numbers to be Integers to prevent math errors
  var page = parseInt(currentPage || 1, 10);
  var globalFocus = parseInt(activeFocus || 0, 10);

  const [parameters, setParameters] = useState([]);
  const [autoMode, setAutoMode] = useState(false);

  const fetchParameters = useCallback(function() {
    var cacheBuster = new Date().getTime();

    fetch('/parameters.json?t=' + cacheBuster)
      .then(function(response) {
        if (!response.ok) throw new Error('HTTP error');
        return response.json();
      })
      .then(function(jsonArray) {
        // Metadata Sync
        var pageData = jsonArray.find(function(obj) { return obj.page !== undefined; });
        if (pageData && onPageChange) onPageChange(pageData.page);

        var focusData = jsonArray.find(function(obj) { return obj.focus !== undefined; });
        if (focusData && onFocusChange) onFocusChange(focusData.focus);

        var autoModeEntry = jsonArray.find(function(obj) { return obj.autoMode !== undefined; });
        if (autoModeEntry !== undefined) {
          setAutoMode(autoModeEntry.autoMode);
          setAutoModeExternal(autoModeEntry.autoMode);
        }

        // Map and save
        var updatedData = jsonArray.map(function(p) {
          return {
            id: p.id,
            name: p.name,
            unit: p.unit,
            value: p.value !== undefined ? p.value : '---'
          };
        });
        setParameters(updatedData);
      })
      .catch(function(e) {
        console.error("Fetch error:", e);
      });
  }, [onPageChange, onFocusChange, setAutoModeExternal]);

  useEffect(function() {
    fetchParameters();
    var intervalId = setInterval(fetchParameters, UPDATE_INTERVAL_MS);
    return function() { clearInterval(intervalId); };
  }, [fetchParameters]);

  if (autoMode) {
    return (
      <div className="parameter-rows-wrapper">
        <div className="autonomous-mode-overlay"><h2>AUTONOMOUS MODE ACTIVE</h2></div>
      </div>
    );
  }

  // --- REPAIRED PAGINATION LOGIC ---
  // Page 1 should start at index 6 (the 7th item)
  var startIndex = SKIP_COUNT + ((page - 1) * ITEMS_PER_PAGE);
  var endIndex = startIndex + ITEMS_PER_PAGE;

  // We filter the parameters to ensure we only have valid data objects
  var displayList = parameters.filter(function(p) { return p.id !== undefined; });
  var paginatedParameters = displayList.slice(startIndex, endIndex);

  return (
    <div className="parameter-rows-wrapper">
      {paginatedParameters.length === 0 ? (
        <div className="no-data">No data for Page {page}</div>
      ) : (
        paginatedParameters.map(function(param, index) {
          // Calculate if this specific item matches the global focus
          // Example: On Page 1, index 0 is actually global index 6.
          var currentItemGlobalIndex = startIndex + index;
          var isFocused = (currentItemGlobalIndex === globalFocus);

          return (
            <div key={param.id || currentItemGlobalIndex} className={"parameter-row " + (isFocused ? "focused" : "")}>
              <div className="parameter-label">{param.name}</div>
              <div className="parameter-value">
                {param.value} <span className="unit">{param.unit}</span>
              </div>
            </div>
          );
        })
      )}
    </div>
  );
};

export default ParameterDisplay;
